import{_ as n,o as i,c as r,ag as t}from"./chunks/framework.DXGyWiRo.js";const p="/images/uebung027.jpg",s="/images/uebung028.jpg",m=JSON.parse('{"title":"Übung Lektion 18","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung18.md","filePath":"lektionen/uebung18.md"}'),a={name:"lektionen/uebung18.md"};function u(d,e,g,h,l,o){return i(),r("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-18" tabindex="-1">Übung Lektion 18 <a class="header-anchor" href="#ubung-lektion-18" aria-label="Permalink to &quot;Übung Lektion 18&quot;">​</a></h1><p>A) Übersetzen Sie das सुभाषित am Beginn der Lektion.</p><p>नास्ति कामसमो व्याधिर्<br> नास्ति मोहसमो रिपुः ।<br> नास्ति क्रोधसमो वह्निर्<br> नास्ति ज्ञानसमं सुखम् ॥</p><p>Es gibt keine Krankheit wie die Liebe,<br> Es gibt keinen Betrüger und Feind wie die Verblendung,<br> Es gibt kein Feuer wie den Zorn,<br> Es gibt kein Glück wie die Erkenntnis.</p><p>B) Übersetzen Sie folgende Tatpuruṣa:</p><p>१. सुकर ३ leicht zu tun</p><p>२. सुकुल n. gute Familie</p><p>३. सुकृति f. gute Tat</p><p>४. अकरण n. Nichttun</p><p>५. दुरिष्ट n. böser Wunsch</p><p>६. दुरिष्टि f. fehlerhaftes Opfer</p><p>७. सुखादित 3 gut gekaut</p><p>८. दुष्कर 3 schwer zu tun</p><p>९. दुर्जय 3 schwer zu besiegen</p><p>१०. सुगत m. gut (durch die Wiedergeburten) Gegangener (= Buddha)</p><p>११. सुजन m. guter Mensch</p><p>१२. दुरुक्ति f. harte Rede</p><p>१३. दुरुपदेश m. schlechte Anweisung</p><p>१४. सुजात 3 wohlgeboren</p><p>१५. सुगुरु 3 sehr schwer</p><p>१६. अनाप्त 3 ungeeignet</p><p>१७. अनीति f. ungehöriges Benehmen</p><p>१८. अनीश्वरत्व n. nicht-HERR-sein</p><p>१९. सुदुःख n. großes Leid</p><p>२०. दुर्जन m. böser Mensch</p><p>२१. दुर्दग्ध 3 schlecht verbrannt</p><p>२२. अतिकृत 3 übertrieben</p><p>२३. सुपुत्र m. guter Sohn</p><p>२४. सुबुद्धि f. gute Einsicht</p><p>२५. दुष्पुत्र m. schlechter Sohn</p><p>२६. दुष्प्रणीत 3 schlecht ausgeführt</p><p>२७. सुमति f. Freundlichkeit</p><p>२८. दुर्लभ 3 schwer zu bekommen</p><p>२९. दुर्वच 3 schwer zu sagen</p><p>३०. दुर्वचन n. schlechte Rede</p><p>३१. अमृत n. Unsterblichkeit, Unsterblichkeitsspeise, Unsterblichkeitstrank</p><p><img src="'+p+'" alt=""><br> Abb.: नास्ति कामसमो व्याधिः<br> Taj Mahal = تاج محل<br> [Bildquelle: US-Air Force, Tech. Sgt. Keith Brown / Wikipedia. Public domain]</p><p>Bitte keine Hilfsmittel benutzen!</p><p>A) Lösen Sie folgende Komposita in Sanskrit auf und geben Sie Übersetzungsvorschläge:</p><p>१. अन्तगत 3 । अन्तं गतः । zu Ende gegangen, Grammatik: auslautend</p><p>२. क्षमाकर 3। क्षेमायाः करः । jemand der Geduldig ist, geduldiges Tun</p><p>३. क्षेमेन्द्र m.। क्षेमस्येन्द्रः । Herr der Ruhe / des Wohlergehens / Friedens</p><p>४. शस्त्रकोपनिरोध m. । शस्त्राणां कोपस्य निरोधः । शस्त्रस्य । शस्त्रेण । Stoppen des Zorns mit dem Schwert = Stoppen des Kampfes</p><p>५. सिंहसंहनन n.। सिंहस्य संहननम् । सिंहानां संहननम्। सिंहेन संहननम् । सिंहैः संहननम् । Töten eines / mehrerer Löwen, Töten durch einen / mehrere Löwen</p><p>६. अरिसिंह m. । सिंह इव अरिः । अरिरेव सिंहः । löwengleicher Feind</p><p>७. आहारनिद्राभय n. ।  आहारो निद्रा भयं च । Essen, Schlafen und Furcht</p><p>८. मृतिसाधनी f. । मृतेः साधनी । मृत्याः । मृतिम् । Tod bewirkende</p><p>९. कुलोपदेश m. । कुलस्योपदेशः । Familienname (Hinweis auf die Familie)</p><p>B) Übersetzen Sie unter Verwendung von Verben der 2. Präsensklasse:</p><p>1. Der Brahmane preist die Göttinnen. ब्राह्मणो देवीः स्तौति । स्तवीति ।</p><p>2. Die Helden gehen auf dem schwer begehbaren Weg ins Dorf der Arier. शूरा दुर्गमेण मार्गेणार्यग्रामं यन्ति ।</p><p>3. Die Hausmagd melkt die Kühe. गृहदासी धेनूर्दोग्धि</p><p>4. Die Feinde der Arier erschlagen die mächtigen Kṣatriyas. आर्यारयो बलवत्क्षत्रियान्घन्ति । आर्यशत्रवो ।</p><p>5. Ein Gespenst isst keine Früchte. भूतं फलानि नात्ति ।</p><p>6. So spricht der, der [den Weg durch die Wiedergeburten] gut gegangen ist zum Jünger. एवं सुगतः श्रावकं वक्ति । ब्रवीति । ब्रूते ।</p><p>C) Geben Sie in Sanskrit die Definition von Yoga auf zwei Weisen: einmal unter Verwendung eines Kompositums, einmal indem Sie das Kompositum auflösen.</p><p>योगश्चित्तवृत्तिनिरोधः । योगश्चित्तस्य वृत्तेर्निरोधः । वृत्तीनां निरोधः ।</p><p>D) Übersetzen Sie:</p><p>(धर्मः) सर्वेषामाहिंसा सत्यं शौचमनसूयानृशंस्यं क्षमा च ॥</p><p>Pflicht aller ist: Gewaltlosigkeit, Wahrhaftigkeit, Reinheit, Nicht über sein Los murren, Freisein von Boshaftigkeit und geduldige Nachsicht.</p><p><img src="'+s+'" alt=""><br> Abb.: दुर्गमो मार्गः<br> Uttarakhand = उत्तराखण्ड<br> [Bildquelle: Peter Davis. -- <a href="http://www.flickr.com/photos/pediddle/327777627/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/pediddle/327777627/</a>. -- Zugriff am 2008-12-22. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',62)])])}const b=n(a,[["render",u]]);export{m as __pageData,b as default};
